let timestamp = 0;
  let threshold = 1000 / freq;
  let lastArgs;
  let timer;

  const invoke = (args, now = Date.now()) => {
    timestamp = now;
    lastArgs = null;
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    fn(...args);
  };

  const throttled = (...args) => {
    const now = Date.now();
    const passed = now - timestamp;
    if (passed >= threshold) {
      invoke(args, now);
    } else {
      lastArgs = args;
      if (!timer) {
        timer = setTimeout(() => {
          timer = null;
          invoke(lastArgs);
        }, threshold - passed);
      }
    }
  };

import {TAU} from '../../helpers/index.js';

// TODO: use elements.ArcElement instead
export class simpleArc {
  constructor(opts) {
    this.x = opts.x;
    this.y = opts.y;
    this.radius = opts.radius;
  }

  pathSegment(ctx, bounds, opts) {
    const {x, y, radius} = this;
    bounds = bounds || {start: 0, end: TAU};
    ctx.arc(x, y, radius, bounds.end, bounds.start, true);
    return !opts.bounds;
  }

  interpolate(point) {
    const {x, y, radius} = this;
    const angle = point.angle;
    return {
      x: x + Math.cos(angle) * radius,
      y: y + Math.sin(angle) * radius,
      angle
    };
  }
}

addTo(map) {
	map.addLayer(this);
	return this;
}

// @method remove: this
// Removes the layer from the map it is currently active on.
remove() {
	return this.removeFrom(this._map || this._mapToAdd);
}

// @method removeFrom(map: LeafletMap): this
// Removes the layer from the given map
//
// @alternative
// @method removeFrom(group: LayerGroup): this
// Removes the layer from the given `LayerGroup`
removeFrom(obj) {
	obj?.removeLayer(this);
	return this;
}

// @method getPane(name? : String): HTMLElement
// Returns the `HTMLElement` representing the named pane on the map. If `name` is omitted, returns the pane for this layer.
getPane(name) {
	return this._map.getPane(name ? (this.options[name] || name) : this.options.pane);
}

function memoize(func, resolver) {
  if (typeof func != 'function' || (resolver != null && typeof resolver != 'function')) {
    throw new TypeError(FUNC_ERROR_TEXT);
  }
  var memoized = function() {
    var args = arguments,
        key = resolver ? resolver.apply(this, args) : args[0],
        cache = memoized.cache;

    if (cache.has(key)) {
      return cache.get(key);
    }
    var result = func.apply(this, args);
    memoized.cache = cache.set(key, result) || cache;
    return result;
  };
  memoized.cache = new (memoize.Cache || MapCache);
  return memoized;
}

function overRest(func, start, transform) {
  start = nativeMax(start === undefined ? (func.length - 1) : start, 0);
  return function() {
    var args = arguments,
        index = -1,
        length = nativeMax(args.length - start, 0),
        array = Array(length);

    while (++index < length) {
      array[index] = args[start + index];
    }
    index = -1;
    var otherArgs = Array(start + 1);
    while (++index < start) {
      otherArgs[index] = args[index];
    }
    otherArgs[start] = transform(array);
    return apply(func, this, otherArgs);
  };
}

function createAssigner(assigner) {
  return baseRest(function(object, sources) {
    var index = -1,
        length = sources.length,
        customizer = length > 1 ? sources[length - 1] : undefined,
        guard = length > 2 ? sources[2] : undefined;

    customizer = (assigner.length > 3 && typeof customizer == 'function')
      ? (length--, customizer)
      : undefined;

    if (guard && isIterateeCall(sources[0], sources[1], guard)) {
      customizer = length < 3 ? undefined : customizer;
      length = 1;
    }
    object = Object(object);
    while (++index < length) {
      var source = sources[index];
      if (source) {
        assigner(object, source, index, customizer);
      }
    }
    return object;
  });
}

function baseFlatten(array, depth, predicate, isStrict, result) {
  var index = -1,
      length = array.length;

  predicate || (predicate = isFlattenable);
  result || (result = []);

  while (++index < length) {
    var value = array[index];
    if (depth > 0 && predicate(value)) {
      if (depth > 1) {
        // Recursively flatten arrays (susceptible to call stack limits).
        baseFlatten(value, depth - 1, predicate, isStrict, result);
      } else {
        arrayPush(result, value);
      }
    } else if (!isStrict) {
      result[result.length] = value;
    }
  }
  return result;
}

export default function setGrabCursor(moving) {
  const swiper = this;
  if (
    !swiper.params.simulateTouch ||
    (swiper.params.watchOverflow && swiper.isLocked) ||
    swiper.params.cssMode
  )
    return;
  const el = swiper.params.touchEventsTarget === 'container' ? swiper.el : swiper.wrapperEl;
  if (swiper.isElement) {
    swiper.__preventObserver__ = true;
  }
  el.style.cursor = 'move';
  el.style.cursor = moving ? 'grabbing' : 'grab';
  if (swiper.isElement) {
    requestAnimationFrame(() => {
      swiper.__preventObserver__ = false;
    });
  }
}

export default function transitionEmit({ swiper, runCallbacks, direction, step }) {
  const { activeIndex, previousIndex } = swiper;
  let dir = direction;
  if (!dir) {
    if (activeIndex > previousIndex) dir = 'next';
    else if (activeIndex < previousIndex) dir = 'prev';
    else dir = 'reset';
  }

  swiper.emit(`transition${step}`);

  if (runCallbacks && dir === 'reset') {
    swiper.emit(`slideResetTransition${step}`);
  } else if (runCallbacks && activeIndex !== previousIndex) {
    swiper.emit(`slideChangeTransition${step}`);
    if (dir === 'next') {
      swiper.emit(`slideNextTransition${step}`);
    } else {
      swiper.emit(`slidePrevTransition${step}`);
    }
  }
}

import { getWindow, getDocument } from 'ssr-window';

let support;

function calcSupport() {
  const window = getWindow();
  const document = getDocument();

  return {
    smoothScroll:
      document.documentElement &&
      document.documentElement.style &&
      'scrollBehavior' in document.documentElement.style,

    touch: !!(
      'ontouchstart' in window ||
      (window.DocumentTouch && document instanceof window.DocumentTouch)
    ),
  };
}

function getSupport() {
  if (!support) {
    support = calcSupport();
  }
  return support;
}

export { getSupport };

function* collectParsersFromLanguages(parserChoices, languages, plugins) {
  const existingParsers = new Set(parserChoices.map((choice) => choice.value));

  for (const language of languages) {
    if (language.parsers) {
      for (const parserName of language.parsers) {
        if (!existingParsers.has(parserName)) {
          existingParsers.add(parserName);
          const plugin = plugins.find(
            (plugin) =>
              plugin.parsers && Object.hasOwn(plugin.parsers, parserName),
          );

          let description = language.name;
          if (plugin?.name) {
            description += ` (plugin: ${plugin.name})`;
          }
          yield { value: parserName, description };
        }
      }
    }
  }
}

function pathMatchesGlobs(filePath, patterns, excludedPatterns) {
  const patternList = Array.isArray(patterns) ? patterns : [patterns];
  // micromatch always matches against basename when the option is enabled
  // use only patterns without slashes with it to match minimatch behavior
  const { withSlashes = [], withoutSlashes = [] } = Object.groupBy(
    patternList,
    (pattern) => (pattern.includes("/") ? "withSlashes" : "withoutSlashes"),
  );

  return (
    micromatch.isMatch(filePath, withoutSlashes, {
      ignore: excludedPatterns,
      basename: true,
      dot: true,
    }) ||
    micromatch.isMatch(filePath, withSlashes, {
      ignore: excludedPatterns,
      basename: false,
      dot: true,
    })
  );
}

async function resolveConfig(fileUrlOrPath, options) {
  options = { useCache: true, ...options };
  const filePath = toPath(fileUrlOrPath);

  const [result, editorConfigured] = await Promise.all([
    loadPrettierConfig(filePath, options),
    loadEditorconfig(filePath, options),
  ]);

  if (!result && !editorConfigured) {
    return null;
  }

  const merged = {
    ...editorConfigured,
    ...mergeOverrides(result, filePath),
  };

  if (Array.isArray(merged.plugins)) {
    merged.plugins = merged.plugins.map((value) =>
      typeof value === "string" && value.startsWith(".") // relative path
        ? path.resolve(path.dirname(result.configFile), value)
        : value,
    );
  }

  return merged;
}

const freezeMethods = (obj) => {
  reduceDescriptors(obj, (descriptor, name) => {
    // skip restricted props in strict mode
    if (isFunction(obj) && ['arguments', 'caller', 'callee'].includes(name)) {
      return false;
    }

    const value = obj[name];

    if (!isFunction(value)) return;

    descriptor.enumerable = false;

    if ('writable' in descriptor) {
      descriptor.writable = false;
      return;
    }

    if (!descriptor.set) {
      descriptor.set = () => {
        throw Error("Can not rewrite read-only method '" + name + "'");
      };
    }
  });
};

function handleApiRequest(req, res) {
  let status;
  let result;
  let data = '';

  req.on('data', (chunk) => {
    data += chunk;
  });

  req.on('end', () => {
    try {
      status = 200;
      result = {
        url: req.url,
        data: data ? JSON.parse(data) : undefined,
        method: req.method,
        headers: req.headers,
      };
    } catch (e) {
      console.error('Error:', e.message);
      status = 400;
      result = {
        error: e.message,
      };
    }

    res.writeHead(status, {
      'Content-Type': 'application/json',
    });
    res.end(JSON.stringify(result));
  });
}

function eachOfArrayLike(coll, iteratee, callback) {
    callback = once(callback);
    var index = 0,
        completed = 0,
        {length} = coll,
        canceled = false;
    if (length === 0) {
        callback(null);
    }

    function iteratorCallback(err, value) {
        if (err === false) {
            canceled = true
        }
        if (canceled === true) return
        if (err) {
            callback(err);
        } else if ((++completed === length) || value === breakLoop) {
            callback(null);
        }
    }

    for (; index < length; index++) {
        iteratee(coll[index], index, onlyOnce(iteratorCallback));
    }
}

export default function timeout(asyncFn, milliseconds, info) {
    var fn = wrapAsync(asyncFn);

    return initialParams((args, callback) => {
        var timedOut = false;
        var timer;

        function timeoutCallback() {
            var name = asyncFn.name || 'anonymous';
            var error  = new Error('Callback function "' + name + '" timed out.');
            error.code = 'ETIMEDOUT';
            if (info) {
                error.info = info;
            }
            timedOut = true;
            callback(error);
        }

        args.push((...cbArgs) => {
            if (!timedOut) {
                callback(...cbArgs);
                clearTimeout(timer);
            }
        });

        // setup timer and call original function
        timer = setTimeout(timeoutCallback, milliseconds);
        fn(...args);
    });
}

function waterfall (tasks, callback) {
    callback = once(callback);
    if (!Array.isArray(tasks)) return callback(new Error('First argument to waterfall must be an array of functions'));
    if (!tasks.length) return callback();
    var taskIndex = 0;

    function nextTask(args) {
        var task = wrapAsync(tasks[taskIndex++]);
        task(...args, onlyOnce(next));
    }

    function next(err, ...args) {
        if (err === false) return
        if (err || taskIndex === tasks.length) {
            return callback(err, ...args);
        }
        nextTask(args);
    }

    nextTask([]);
}

function addDeclaredGlobals(
	scopeManager,
	configGlobals = Object.create(null),
	inlineGlobals = Object.create(null),
) {
	const finalGlobals = { __proto__: null, ...configGlobals };

	for (const [name, data] of Object.entries(inlineGlobals)) {
		finalGlobals[name] = data.value;
	}

	const names = Object.keys(finalGlobals).filter(
		name => finalGlobals[name] !== "off",
	);

	scopeManager.addGlobals(names);

	const globalScope = scopeManager.scopes[0];

	for (const name of names) {
		const variable = globalScope.set.get(name);

		variable.eslintImplicitGlobalSetting = configGlobals[name];
		variable.eslintExplicitGlobal = !!inlineGlobals[name];
		variable.eslintExplicitGlobalComments = inlineGlobals[name]?.comments;
		variable.writeable = finalGlobals[name] === "writable";
	}
}

function normalizeMultiArgReportCall(...args) {
	// If there is one argument, it is considered to be a new-style call already.
	if (args.length === 1) {
		// Shallow clone the object to avoid surprises if reusing the descriptor
		return Object.assign({}, args[0]);
	}

	// If the second argument is a string, the arguments are interpreted as [node, message, data, fix].
	if (typeof args[1] === "string") {
		return {
			node: args[0],
			message: args[1],
			data: args[2],
			fix: args[3],
		};
	}

	// Otherwise, the arguments are interpreted as [node, loc, message, data, fix].
	return {
		node: args[0],
		loc: args[1],
		message: args[2],
		data: args[3],
		fix: args[4],
	};
}

function getDirectiveCommentsForFlatConfig(
	sourceCode,
	ruleMapper,
	language,
	report,
) {
	const disableDirectives = [];

	if (sourceCode.getDisableDirectives) {
		const { directives: directivesSources, problems: directivesProblems } =
			sourceCode.getDisableDirectives();

		if (Array.isArray(directivesProblems)) {
			directivesProblems.forEach(problem => report.addError(problem));
		}

		directivesSources.forEach(directive => {
			const directives = createDisableDirectives(
				directive,
				ruleMapper,
				language,
				sourceCode,
				report,
			);

			disableDirectives.push(...directives);
		});
	}

	return disableDirectives;
}

function assertInvalidTestCase(
	item,
	seenTestCases,
	ruleName,
	assertionOptions = {},
) {
	assertTestCommonProperties(item);

	assertErrorsProperty(item.errors, ruleName, assertionOptions);

	// 'output' is optional, but if it exists it must be a string or null
	if (hasOwnProperty(item, "output")) {
		assert.ok(
			item.output === null || typeof item.output === "string",
			"Test property 'output', if specified, must be a string or null. If no autofix is expected, then omit the 'output' property or set it to null.",
		);
	}

	checkDuplicateTestCase(item, seenTestCases);
}

function equalsToOriginalName(node) {
	const localName = node.name;
	const valueNode =
		node.parent.type === "AssignmentPattern" ? node.parent : node;
	const parent = valueNode.parent;

	switch (parent.type) {
		case "Property":
			return (
				(parent.parent.type === "ObjectPattern" ||
					parent.parent.type === "ObjectExpression") &&
				parent.value === valueNode &&
				!parent.computed &&
				parent.key.type === "Identifier" &&
				parent.key.name === localName
			);

		case "ImportSpecifier":
			return (
				parent.local === node &&
				astUtils.getModuleExportName(parent.imported) ===
					localName
			);

		default:
			return false;
	}
}

function processComment(comment) {
	const options = normalizedOptions[comment.type],
		commentValid = isCommentValid(comment, options);

	if (!commentValid) {
		const messageId =
			capitalize === "always"
				? "unexpectedLowercaseComment"
				: "unexpectedUppercaseComment";

		context.report({
			node: null, // Intentionally using loc instead
			loc: comment.loc,
			messageId,
			fix(fixer) {
				const match = comment.value.match(LETTER_PATTERN);
				const char = match[0];

				// Offset match.index by 2 to account for the first 2 characters that start the comment (// or /*)
				const charIndex = comment.range[0] + match.index + 2;

				return fixer.replaceTextRange(
					[charIndex, charIndex + char.length],
					capitalize === "always"
						? char.toLocaleUpperCase()
						: char.toLocaleLowerCase(),
				);
			},
		});
	}
}

function handleFunction(node) {
	// Skip recursive functions.
	const nameVar = sourceCode.getDeclaredVariables(node)[0];

	if (isFunctionName(nameVar) && nameVar.references.length > 0) {
		return;
	}

	const hasName = Boolean(node.id && node.id.name);
	const config = getConfigForNode(node);

	if (config === "never") {
		if (hasName && node.type !== "FunctionDeclaration") {
			reportUnexpectedNamedFunction(node);
		}
	} else if (config === "as-needed") {
		if (!hasName && !hasInferredName(node)) {
			reportUnexpectedUnnamedFunction(node);
		}
	} else {
		if (!hasName && !isObjectOrClassMethod(node)) {
			reportUnexpectedUnnamedFunction(node);
		}
	}
}

function isOverloadedFunction(node) {
	const functionName = node.id.name;

	if (node.parent.type === "ExportNamedDeclaration") {
		return node.parent.parent.body.some(
			member =>
				member.type === "ExportNamedDeclaration" &&
				member.declaration?.type === "TSDeclareFunction" &&
				member.declaration.id.name === functionName,
		);
	}

	if (node.parent.type === "SwitchCase") {
		return node.parent.parent.cases.some(switchCase =>
			switchCase.consequent.some(
				member =>
					member.type === "TSDeclareFunction" &&
					member.id.name === functionName,
			),
		);
	}

	return (
		Array.isArray(node.parent.body) &&
		node.parent.body.some(
			member =>
				member.type === "TSDeclareFunction" &&
				member.id.name === functionName,
		)
	);
}

function checkArguments(node, checker) {
	for (let i = 1; i < node.arguments.length; i++) {
		const prevArgToken = sourceCode.getLastToken(
			node.arguments[i - 1],
		);
		const currentArgToken = sourceCode.getFirstToken(
			node.arguments[i],
		);

		if (checker.check(prevArgToken, currentArgToken)) {
			const tokenBefore = sourceCode.getTokenBefore(
				currentArgToken,
				{ includeComments: true },
			);

			const hasLineCommentBefore = tokenBefore.type === "Line";

			context.report({
				node,
				loc: {
					start: tokenBefore.loc.end,
					end: currentArgToken.loc.start,
				},
				messageId: checker.messageId,
				fix: hasLineCommentBefore
					? null
					: checker.createFix(currentArgToken, tokenBefore),
			});
		}
	}
}

function check(node) {
	if (node.arguments.length < 2) {
		return;
	}

	const option = context.options[0] || "always";

	if (option === "never") {
		checkArguments(node, checkers.unexpected);
	} else if (option === "always") {
		checkArguments(node, checkers.missing);
	} else if (option === "consistent") {
		const firstArgToken = sourceCode.getLastToken(
			node.arguments[0],
		);
		const secondArgToken = sourceCode.getFirstToken(
			node.arguments[1],
		);

		if (
			firstArgToken.loc.end.line === secondArgToken.loc.start.line
		) {
			checkArguments(node, checkers.unexpected);
		} else {
			checkArguments(node, checkers.missing);
		}
	}
}

function validateArguments(parens, elements) {
	const leftParen = parens.leftParen;
	const tokenAfterLeftParen = sourceCode.getTokenAfter(leftParen);
	const hasLeftNewline = !astUtils.isTokenOnSameLine(
		leftParen,
		tokenAfterLeftParen,
	);
	const needsNewlines = shouldHaveNewlines(elements, hasLeftNewline);

	for (let i = 0; i <= elements.length - 2; i++) {
		const currentElement = elements[i];
		const nextElement = elements[i + 1];
		const hasNewLine =
			currentElement.loc.end.line !== nextElement.loc.start.line;

		if (!hasNewLine && needsNewlines) {
			context.report({
				node: currentElement,
				messageId: "expectedBetween",
				fix: fixer => fixer.insertTextBefore(nextElement, "\n"),
			});
		}
	}
}

function checkSpacing(kind, side, leftToken, rightToken) {
	if (
		!!(rightToken.range[0] - leftToken.range[1]) !==
		modes[kind][side]
	) {
		const after = leftToken.value === "*";
		const spaceRequired = modes[kind][side];
		const node = after ? leftToken : rightToken;
		const messageId = `${spaceRequired ? "missing" : "unexpected"}${capitalize(side)}`;

		context.report({
			node,
			messageId,
			fix(fixer) {
				if (spaceRequired) {
					if (after) {
						return fixer.insertTextAfter(node, " ");
					}
					return fixer.insertTextBefore(node, " ");
				}
				return fixer.removeRange([
					leftToken.range[1],
					rightToken.range[0],
				]);
			},
		});
	}
}
